def findLeaves(root):
    res = []
    def dfs(node):
        if not node: return -1
        h = max(dfs(node.left), dfs(node.right)) + 1
        if h >= len(res): res.append([])
        res[h].append(node.val)
        return h
    dfs(root); return res

